const msg = $input.first().json.message;
const chatId = msg.chat.id;
const text = msg.text || '';
const sd = $getWorkflowStaticData('global');
if (!sd.spend) sd.spend = { total_usd: 0, limit_usd: parseFloat(process.env.API_LIMIT_USD || '5'), anthropic_usd: 0, openai_usd: 0 };

if (text.startsWith('/setlimit')) {
  const val = parseFloat(text.split(' ')[1] || '');
  if (!isNaN(val) && val > 0) {
    sd.spend.limit_usd = val;
    return [{ json: { chatId, replyType: 'info', replyText: `✅ Spend limit set to $${val.toFixed(2)}` } }];
  }
  return [{ json: { chatId, replyType: 'info', replyText: '❌ Usage: /setlimit 10.0' } }];
}

if (text.startsWith('/resetspend')) {
  sd.spend.total_usd = 0; sd.spend.anthropic_usd = 0; sd.spend.openai_usd = 0;
  return [{ json: { chatId, replyType: 'info', replyText: '✅ Spend reset to $0.00' } }];
}

if (text.startsWith('/spend')) {
  const sp = sd.spend;
  const pct = Math.min(sp.total_usd / sp.limit_usd * 100, 100).toFixed(1);
  const filled = Math.floor(pct / 10);
  const bar = '█'.repeat(filled) + '░'.repeat(10 - filled);
  return [{ json: { chatId, replyType: 'info', replyText: `💰 *Spend Report*\n${bar} ${pct}%\nTotal: $${sp.total_usd.toFixed(4)} / $${sp.limit_usd.toFixed(2)}\nAnthropic: $${sp.anthropic_usd.toFixed(4)}\nOpenAI: $${(sp.openai_usd || 0).toFixed(4)}` } }];
}

return [{ json: { chatId, text, replyType: 'menu' } }];

const cb = $input.first().json.callback_query;
const chatId = cb.message.chat.id;
const data = cb.data;
const callbackQueryId = cb.id;
const sd = $getWorkflowStaticData('global');
if (!sd.command_queue) sd.command_queue = [];

const enqueue = (cmd) => {
  if (sd.command_queue.length >= 50) sd.command_queue.shift();
  sd.command_queue.push(cmd);
};

let action = null, replyMenu = null;

if (data.startsWith('cmd:')) {
  const type = data.slice(4);
  enqueue({ command_id: require('crypto').randomUUID(), chat_id: String(chatId), type, payload: {} });
  action = 'queued';
} else if (data.startsWith('app:')) {
  enqueue({ command_id: require('crypto').randomUUID(), chat_id: String(chatId), type: 'launch-app', payload: { app: data.slice(4) } });
  action = 'queued';
} else if (data.startsWith('chrome:')) {
  enqueue({ command_id: require('crypto').randomUUID(), chat_id: String(chatId), type: 'chrome-profile', payload: { profile_directory: data.slice(7) } });
  action = 'queued';
} else if (data === 'menu:apps') { replyMenu = 'apps'; action = 'show_menu';
} else if (data === 'menu:chrome') {
  enqueue({ command_id: require('crypto').randomUUID(), chat_id: String(chatId), type: 'chrome-profiles-list', payload: {} });
  replyMenu = 'chrome'; action = 'show_menu';
} else if (data === 'menu:accounts') { replyMenu = 'accounts'; action = 'show_menu';
} else if (data === 'menu:terminal') { action = 'ask_terminal';
} else if (data === 'menu:install') { action = 'ask_install';
} else if (data.startsWith('account:')) {
  sd.active_account = parseInt(data.slice(8));
  action = 'account_switched';
}

return [{ json: { chatId, callbackQueryId, action, replyMenu, active_account: sd.active_account || 1 } }];

const { chatId, callbackQueryId, action, replyMenu, active_account } = $input.first().json;
const sd = $getWorkflowStaticData('global');
let text = '', replyMarkup = null;

if (action === 'queued') { text = '⏳ Command queued…';
} else if (action === 'account_switched') { text = `✅ Switched to Account ${active_account}`;
} else if (action === 'ask_terminal') {
  text = '💻 Send the terminal command as a message:';
  if (!sd.pending) sd.pending = {};
  sd.pending[String(chatId)] = { type: 'terminal' };
} else if (action === 'ask_install') {
  text = '📦 Send the download URL (.exe / .msi / .zip):';
  if (!sd.pending) sd.pending = {};
  sd.pending[String(chatId)] = { type: 'install' };
} else if (replyMenu === 'apps') {
  text = '🚀 Choose an app:';
  replyMarkup = { inline_keyboard: [
    [{ text: 'Cursor', callback_data: 'app:cursor' }, { text: 'VS Code', callback_data: 'app:vscode' }],
    [{ text: 'Claude Code', callback_data: 'app:claude-code' }, { text: 'Antigravity', callback_data: 'app:antigravity' }],
    [{ text: 'Terminal', callback_data: 'app:terminal' }]
  ]};
} else if (replyMenu === 'chrome') {
  const profiles = sd.chrome_profiles || [];
  if (profiles.length === 0) { text = '🌐 Fetching profiles… retry in a moment.'; }
  else { text = '🌐 Chrome Profiles:'; replyMarkup = { inline_keyboard: profiles.map(p => [{ text: p.display, callback_data: `chrome:${p.directory}` }]) }; }
} else if (replyMenu === 'accounts') {
  const active = active_account || 1;
  text = `🔑 Select Claude Account (active: #${active}):`;
  replyMarkup = { inline_keyboard: [
    [{ text: `Account 1 ${active===1?'✓':''}`, callback_data: 'account:1' }],
    [{ text: `Account 2 ${active===2?'✓':''}`, callback_data: 'account:2' }],
    [{ text: `Account 3 ${active===3?'✓':''}`, callback_data: 'account:3' }]
  ]};
}
return [{ json: { chatId, callbackQueryId, text, replyMarkup } }];

const msg = $input.first().json.message;
const voice = msg.voice;
return [{ json: {
  chatId: String(msg.chat.id),
  fileId: voice.file_id,
  duration: voice.duration || 0,
  mimeType: voice.mime_type || 'audio/ogg'
} }];

// Download voice from Telegram and transcribe with OpenAI Whisper
const https = require('https');
const { chatId, fileId, duration } = $input.first().json;
const botToken = process.env.TELEGRAM_BOT_TOKEN;
const openaiKey = process.env.OPENAI_API_KEY;

if (!openaiKey) {
  const sd = $getWorkflowStaticData('global');
  if (!sd.history) sd.history = {};
  if (!sd.history[chatId]) sd.history[chatId] = [];
  sd.history[chatId].push({ role: 'user', content: '[Voice message received — OpenAI key not set for transcription]' });
  if (sd.history[chatId].length > 20) sd.history[chatId] = sd.history[chatId].slice(-20);
  return [{ json: { chatId, mode: 'ai', messages: sd.history[chatId], activeAccount: 1 } }];
}

function httpGet(url) {
  return new Promise((resolve, reject) => {
    https.get(url, res => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => resolve(Buffer.concat(chunks)));
      res.on('error', reject);
    }).on('error', reject);
  });
}

function whisperMultipart(audioBuffer, openaiKey) {
  const boundary = 'dispatch' + Date.now();
  const header = Buffer.from(
    `--${boundary}\r\nContent-Disposition: form-data; name="model"\r\n\r\nwhisper-1\r\n` +
    `--${boundary}\r\nContent-Disposition: form-data; name="file"; filename="voice.ogg"\r\nContent-Type: audio/ogg\r\n\r\n`
  );
  const footer = Buffer.from(`\r\n--${boundary}--\r\n`);
  const body = Buffer.concat([header, audioBuffer, footer]);
  return new Promise((resolve, reject) => {
    const req = https.request({
      hostname: 'api.openai.com', path: '/v1/audio/transcriptions', method: 'POST',
      headers: {
        'Authorization': `Bearer ${openaiKey}`,
        'Content-Type': `multipart/form-data; boundary=${boundary}`,
        'Content-Length': body.length
      }
    }, res => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => { try { resolve(JSON.parse(Buffer.concat(chunks).toString())); } catch(e) { reject(e); } });
      res.on('error', reject);
    });
    req.on('error', reject);
    req.write(body); req.end();
  });
}

// 1. Get Telegram file path
const fileInfoBuf = await httpGet(`https://api.telegram.org/bot${botToken}/getFile?file_id=${fileId}`);
const fileInfo = JSON.parse(fileInfoBuf.toString());
if (!fileInfo.ok || !fileInfo.result?.file_path) {
  throw new Error('Telegram getFile failed: ' + fileInfoBuf.toString());
}

// 2. Download OGG audio
const audioBuf = await httpGet(`https://api.telegram.org/file/bot${botToken}/${fileInfo.result.file_path}`);

// 3. Transcribe
const whisperResp = await whisperMultipart(audioBuf, openaiKey);
const transcript = whisperResp.text || '(transcription failed)';

// 4. Track Whisper cost
const sd = $getWorkflowStaticData('global');
if (!sd.spend) sd.spend = { total_usd: 0, limit_usd: parseFloat(process.env.API_LIMIT_USD || '5'), anthropic_usd: 0, openai_usd: 0 };
const minutes = Math.max(Math.ceil((duration || 1) / 60), 1);
const cost = minutes * 0.006;
sd.spend.openai_usd = (sd.spend.openai_usd || 0) + cost;
sd.spend.total_usd = (sd.spend.total_usd || 0) + cost;

// 5. Add transcript to history
if (!sd.history) sd.history = {};
if (!sd.history[chatId]) sd.history[chatId] = [];
sd.history[chatId].push({ role: 'user', content: transcript });
if (sd.history[chatId].length > 20) sd.history[chatId] = sd.history[chatId].slice(-20);

return [{ json: {
  chatId, mode: 'ai',
  messages: sd.history[chatId],
  activeAccount: sd.active_account || 1,
  _voiceTranscript: transcript
} }];

const msg = $input.first().json.message;
const chatId = String(msg.chat.id);
const text = msg.text;
const sd = $getWorkflowStaticData('global');
if (!sd.pending) sd.pending = {};
if (!sd.history) sd.history = {};

const pending = sd.pending[chatId];
if (pending) {
  delete sd.pending[chatId];
  const commandId = require('crypto').randomUUID();
  if (!sd.command_queue) sd.command_queue = [];
  let cmd;
  if (pending.type === 'terminal') cmd = { command_id: commandId, chat_id: chatId, type: 'terminal', payload: { command: text } };
  else if (pending.type === 'install') cmd = { command_id: commandId, chat_id: chatId, type: 'install', payload: { url: text } };
  if (cmd) {
    if (sd.command_queue.length >= 50) sd.command_queue.shift();
    sd.command_queue.push(cmd);
  }
  return [{ json: { chatId, mode: 'queued', text: `⏳ ${pending.type} queued…` } }];
}

if (!sd.history[chatId]) sd.history[chatId] = [];
sd.history[chatId].push({ role: 'user', content: text });
if (sd.history[chatId].length > 20) sd.history[chatId] = sd.history[chatId].slice(-20);
return [{ json: { chatId, mode: 'ai', messages: sd.history[chatId], activeAccount: sd.active_account || 1 } }];

// Check if under spend limit before AI call
const input = $input.first().json;
const sd = $getWorkflowStaticData('global');
if (!sd.spend) sd.spend = { total_usd: 0, limit_usd: parseFloat(process.env.API_LIMIT_USD || '5'), anthropic_usd: 0, openai_usd: 0 };
if (!sd.spend.limit_usd) sd.spend.limit_usd = parseFloat(process.env.API_LIMIT_USD || '5');
const underLimit = sd.spend.total_usd < sd.spend.limit_usd;
return [{ json: { ...input, _underLimit: underLimit, _limitUsd: sd.spend.limit_usd, _spentUsd: sd.spend.total_usd } }];

