// Semantic context from Qdrant (if configured), else pass through
// Cost savings: replace 20-message history with 3 semantically-relevant past exchanges
const https = require('https');
const { chatId, messages, activeAccount } = $input.first().json;
const qdrantUrl = (process.env.QDRANT_URL || '').trim().replace(/\/$/, '');
const qdrantKey = process.env.QDRANT_API_KEY || '';
const openaiKey = process.env.OPENAI_API_KEY || '';
const collection = process.env.QDRANT_COLLECTION || 'dispatch_memory';

function postJsonRaw(hostname, port, path, headers, body) {
  const data = typeof body === 'string' ? body : JSON.stringify(body);
  return new Promise((resolve, reject) => {
    const req = https.request({ hostname, port: port || 443, path, method: 'POST', headers: {
      ...headers, 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(data)
    }}, res => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => { try { resolve(JSON.parse(Buffer.concat(chunks).toString())); } catch(e) { resolve({}); } });
      res.on('error', resolve);
    });
    req.on('error', resolve);
    req.write(data); req.end();
  });
}

let contextMessages = messages;

if (qdrantUrl && openaiKey) {
  try {
    const lastUserMsg = [...messages].reverse().find(m => m.role === 'user')?.content || '';
    if (lastUserMsg) {
      // Embed the user query
      const embedResp = await postJsonRaw('api.openai.com', 443, '/v1/embeddings',
        { 'Authorization': `Bearer ${openaiKey}` },
        { model: 'text-embedding-3-small', input: lastUserMsg }
      );
      const vector = embedResp.data?.[0]?.embedding;

      if (vector) {
        // Track embedding cost ($0.02/1M tokens)
        const sd = $getWorkflowStaticData('global');
        if (sd.spend) {
          const estTokens = Math.ceil(lastUserMsg.length / 4);
          const cost = estTokens / 1_000_000 * 0.02;
          sd.spend.openai_usd = (sd.spend.openai_usd || 0) + cost;
          sd.spend.total_usd = (sd.spend.total_usd || 0) + cost;
        }

        // Parse Qdrant URL for host/port/path
        const urlObj = new URL(`${qdrantUrl}/collections/${collection}/points/search`);
        const searchResp = await postJsonRaw(
          urlObj.hostname, parseInt(urlObj.port) || 443, urlObj.pathname,
          qdrantKey ? { 'api-key': qdrantKey } : {},
          { vector, limit: 3, with_payload: true, score_threshold: 0.75,
            filter: { must: [{ key: 'chat_id', match: { value: chatId } }] } }
        );

        const hits = searchResp.result || [];
        if (hits.length > 0) {
          const pastCtx = hits
            .map(h => `Q: ${h.payload.user_msg}\nA: ${h.payload.assistant_msg}`)
            .join('\n---\n');
          // Replace full 20-msg history with 3 relevant past + last 4 messages
          contextMessages = [
            { role: 'user', content: `[Relevant past context]:\n${pastCtx}` },
            { role: 'assistant', content: 'I recall.' },
            ...messages.slice(-4)
          ];
        }
      }
    }
  } catch (_) { /* Qdrant unavailable — use full history */ }
}

return [{ json: { chatId, messages: contextMessages, activeAccount } }];

// Call Anthropic API, track spend, update history
const https = require('https');
const { chatId, messages, activeAccount } = $input.first().json;

const apiKey = [
  process.env.ANTHROPIC_API_KEY_1,
  process.env.ANTHROPIC_API_KEY_2,
  process.env.ANTHROPIC_API_KEY_3
][( activeAccount || 1) - 1] || process.env.ANTHROPIC_API_KEY_1;

const reqBody = JSON.stringify({
  model: 'claude-haiku-4-5-20251001',
  max_tokens: 1024,
  system: 'You are a helpful assistant for a Windows PC remote-control agent. Be concise. The user controls their PC via Telegram.',
  messages
});

const resp = await new Promise((resolve, reject) => {
  const req = https.request({
    hostname: 'api.anthropic.com', path: '/v1/messages', method: 'POST',
    headers: {
      'x-api-key': apiKey,
      'anthropic-version': '2023-06-01',
      'Content-Type': 'application/json',
      'Content-Length': Buffer.byteLength(reqBody)
    }
  }, res => {
    const chunks = [];
    res.on('data', c => chunks.push(c));
    res.on('end', () => { try { resolve(JSON.parse(Buffer.concat(chunks).toString())); } catch(e) { reject(e); } });
    res.on('error', reject);
  });
  req.on('error', reject);
  req.write(reqBody); req.end();
});

const reply = resp.content?.[0]?.text || resp.error?.message || '(no response)';
const usage = resp.usage || { input_tokens: 0, output_tokens: 0 };

// Track Anthropic cost (Haiku: in=$0.80/M, out=$4.00/M)
const sd = $getWorkflowStaticData('global');
if (!sd.spend) sd.spend = { total_usd: 0, limit_usd: 5, anthropic_usd: 0, openai_usd: 0 };
const cost = (usage.input_tokens / 1_000_000 * 0.80) + (usage.output_tokens / 1_000_000 * 4.00);
sd.spend.anthropic_usd = (sd.spend.anthropic_usd || 0) + cost;
sd.spend.total_usd = (sd.spend.total_usd || 0) + cost;

// Save assistant reply to history
if (!sd.history) sd.history = {};
if (!sd.history[chatId]) sd.history[chatId] = [];
sd.history[chatId].push({ role: 'assistant', content: reply });
if (sd.history[chatId].length > 20) sd.history[chatId] = sd.history[chatId].slice(-20);

return [{ json: { chatId, reply, inputTokens: usage.input_tokens, outputTokens: usage.output_tokens, cost } }];

// Store this exchange in Qdrant for future semantic retrieval
const https = require('https');
const { chatId, reply } = $input.first().json;
const qdrantUrl = (process.env.QDRANT_URL || '').trim().replace(/\/$/, '');
const qdrantKey = process.env.QDRANT_API_KEY || '';
const openaiKey = process.env.OPENAI_API_KEY || '';
const collection = process.env.QDRANT_COLLECTION || 'dispatch_memory';

const sd = $getWorkflowStaticData('global');
const history = sd.history?.[chatId] || [];
// Get last user message (second-to-last item, since assistant reply was just appended)
const userMsg = [...history].reverse().find(m => m.role === 'user')?.content || '';

if (qdrantUrl && openaiKey && userMsg && reply && reply !== '(no response)') {
  try {
    const exchangeText = `User: ${userMsg}\nAssistant: ${reply}`;

    function postJson(hostname, port, path, method, headers, body) {
      const data = JSON.stringify(body);
      return new Promise((resolve, reject) => {
        const req = https.request({ hostname, port: port || 443, path, method, headers: {
          ...headers, 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(data)
        }}, res => {
          const chunks = [];
          res.on('data', c => chunks.push(c));
          res.on('end', () => { try { resolve(JSON.parse(Buffer.concat(chunks).toString())); } catch(e) { resolve({}); } });
          res.on('error', resolve);
        });
        req.on('error', resolve);
        req.write(data); req.end();
      });
    }

    // Embed the exchange
    const embedResp = await postJson('api.openai.com', 443, '/v1/embeddings', 'POST',
      { 'Authorization': `Bearer ${openaiKey}` },
      { model: 'text-embedding-3-small', input: exchangeText }
    );
    const vector = embedResp.data?.[0]?.embedding;

    if (vector) {
      // Track embedding cost
      if (sd.spend) {
        const cost = Math.ceil(exchangeText.length / 4) / 1_000_000 * 0.02;
        sd.spend.openai_usd = (sd.spend.openai_usd || 0) + cost;
        sd.spend.total_usd = (sd.spend.total_usd || 0) + cost;
      }

      const urlObj = new URL(`${qdrantUrl}/collections/${collection}/points`);
      await postJson(
        urlObj.hostname, parseInt(urlObj.port) || 443, urlObj.pathname, 'PUT',
        qdrantKey ? { 'api-key': qdrantKey } : {},
        { points: [{ id: Date.now(), vector, payload: {
          chat_id: chatId, user_msg: userMsg, assistant_msg: reply, ts: new Date().toISOString()
        }}] }
      );
    }
  } catch (_) { /* silent fail */ }
}

return [{ json: { chatId, reply } }];

